class Solution:
    def lengthAfterTransformations(self, s, t, nums):
        MOD = 10 ** 9 + 7
        cur = s
        for _ in range(t):
            nxt = []
            for ch in cur:
                idx = ord(ch) - 97
                cnt = nums[idx]
                for d in range(1, cnt + 1):
                    nxt.append(chr(97 + (idx + d) % 26))
            cur = ''.join(nxt)
        return len(cur) % MOD

