class Solution:
    def lengthAfterTransformations(self, s: str, t: int, nums: List[int]) -> int:
        MOD = 10 ** 9 + 7

        def matmul(a, b):
            n = len(a)
            k = len(b)
            m = len(b[0])
            c = [[0] * m for _ in range(n)]
            for i in range(n):
                ai = a[i]
                ci = c[i]
                for x in range(k):
                    av = ai[x]
                    if av == 0:
                        continue
                    bx = b[x]
                    for j in range(m):
                        ci[j] = (ci[j] + av * bx[j]) % MOD
            return c

        def matpow(mat, p):
            n = len(mat)
            result = [[1 if i == j else 0 for j in range(n)] for i in range(n)]
            base = mat
            while p > 0:
                if p & 1:
                    result = matmul(result, base)
                base = matmul(base, base)
                p >>= 1
            return result

        m = [[0] * 26 for _ in range(26)]
        for i in range(26):
            for d in range(1, nums[i] + 1):
                m[(i + d) % 26][i] = 1
        mt = matpow(m, t)
        cnt = [0] * 26
        for ch in s:
            cnt[ord(ch) - 97] += 1
        total = 0
        for r in range(26):
            row = mt[r]
            acc = 0
            for c in range(26):
                if row[c]:
                    acc += row[c] * cnt[c]
            total = (total + acc) % MOD
        return total

