var lengthAfterTransformations = function(s, t, nums) {
    const MOD = 1000000007n;
    const matmul = (a, b) => {
        const n = a.length, k = b.length, m = b[0].length;
        const c = Array.from({ length: n }, () => new Array(m).fill(0n));
        for (let i = 0; i < n; i++) {
            for (let x = 0; x < k; x++) {
                const av = a[i][x];
                if (av === 0n) continue;
                for (let j = 0; j < m; j++) {
                    c[i][j] = (c[i][j] + av * b[x][j]) % MOD;
                }
            }
        }
        return c;
    };
    const matpow = (mat, p) => {
        const n = mat.length;
        let result = Array.from({ length: n }, (_, i) => Array.from({ length: n }, (_, j) => (i === j ? 1n : 0n)));
        let base = mat;
        while (p > 0) {
            if (p & 1) result = matmul(result, base);
            base = matmul(base, base);
            p = Math.floor(p / 2);
        }
        return result;
    };
    const m = Array.from({ length: 26 }, () => new Array(26).fill(0n));
    for (let i = 0; i < 26; i++) {
        for (let d = 1; d <= nums[i]; d++) {
            m[(i + d) % 26][i] = 1n;
        }
    }
    const mt = matpow(m, t);
    const cnt = new Array(26).fill(0n);
    for (const ch of s) cnt[ch.charCodeAt(0) - 97] += 1n;
    let total = 0n;
    for (let r = 0; r < 26; r++) {
        let acc = 0n;
        for (let c = 0; c < 26; c++) {
            if (mt[r][c]) acc += mt[r][c] * cnt[c];
        }
        total = (total + acc) % MOD;
    }
    return Number(total);
};
